import 'dart:convert';
import 'dart:io';

typedef JsonMap = Map<String, dynamic>;

const _manifestPath = 'tool/visibility/visibility_manifest.json';
const _generatedNotice =
    'Generated by dart run tool/visibility/generate_visibility.dart. '
    'Edit tool/visibility/visibility_manifest.json instead.';

void main(List<String> args) {
  final check = args.contains('--check');
  final manifest = _readManifest();
  final outputs = _generateOutputs(manifest);

  var failed = false;
  for (final entry in outputs.entries) {
    final file = File(entry.key);
    if (check) {
      if (!file.existsSync()) {
        stderr.writeln('Missing generated file: ${entry.key}');
        failed = true;
        continue;
      }
      final current = file.readAsStringSync();
      if (current != entry.value) {
        stderr.writeln('Generated file is stale: ${entry.key}');
        failed = true;
      }
    } else {
      file.parent.createSync(recursive: true);
      file.writeAsStringSync(entry.value);
      stdout.writeln('wrote ${entry.key}');
    }
  }

  if (check && failed) {
    stderr.writeln(
      'Run `dart run tool/visibility/generate_visibility.dart` '
      'and commit the generated files.',
    );
    exitCode = 1;
  } else if (check) {
    stdout.writeln('Visibility files are in sync.');
  }
}

JsonMap _readManifest() {
  final file = File(_manifestPath);
  if (!file.existsSync()) {
    throw StateError('Missing $_manifestPath');
  }
  return jsonDecode(file.readAsStringSync()) as JsonMap;
}

Map<String, String> _generateOutputs(JsonMap manifest) {
  final outputs = <String, String>{
    'llms.txt': _llms(manifest),
    'llms-full.txt': _llmsFull(manifest),
    'identity.json': _identityJson(manifest),
    'developer-ai.txt': _developerAi(manifest),
    'faq-ai.txt': _faqAi(manifest),
    'ai.txt': _aiGuidance(manifest),
    'robots-ai.txt': _robotsAi(manifest),
    'robots.txt': _robots(manifest),
    '.github/copilot-instructions.md': _copilotInstructions(manifest),
    '.github/instructions/pqforge-crypto.instructions.md':
        _copilotCryptoInstructions(manifest),
    '.cursor/rules/pqforge.mdc': _cursorRule(manifest),
    '.windsurfrules': _windsurfRules(manifest),
    'site/index.html': _siteIndex(manifest),
    'site/404.html': _siteNotFound(manifest),
    'site/styles.css': _siteCss(),
    'site/assets/pqforge-protocol.svg': _protocolSvg(),
    'site/favicon.svg': _faviconSvg(),
    'site/sitemap.xml': _sitemap(manifest),
  };

  for (final path in [
    'llms.txt',
    'llms-full.txt',
    'identity.json',
    'developer-ai.txt',
    'faq-ai.txt',
    'ai.txt',
    'robots-ai.txt',
    'robots.txt',
  ]) {
    outputs['site/$path'] = outputs[path]!;
  }

  return outputs;
}

String _llms(JsonMap manifest) {
  final project = _map(manifest['project']);
  final docs = _maps(manifest['docs']);
  final recipes = _maps(manifest['recipes']);
  final doesNotProvide = _strings(manifest['does_not_provide']);
  final forbidden = _strings(
    _map(manifest['evidence_boundary'])['forbidden_claims'],
  );

  final buffer = StringBuffer()
    ..writeln(_mdComment())
    ..writeln('# ${project['short_title']}')
    ..writeln()
    ..writeln('> ${project['tagline']}')
    ..writeln(
      '> Version ${project['version']}; ${project['license']} licensed.',
    )
    ..writeln()
    ..writeln(project['summary'])
    ..writeln()
    ..writeln('## Start Here')
    ..writeln()
    ..writeln('- Website: ${project['canonical_url']}')
    ..writeln('- Repository: ${project['repository']}')
    ..writeln('- Package: ${project['pub_dev']}')
    ..writeln('- API docs: ${project['api_docs']}')
    ..writeln('- Wiki: ${project['wiki']}')
    ..writeln()
    ..writeln('## Key Boundary')
    ..writeln()
    ..writeln(
      '- pqforge composes pqcrypto ML-KEM/ML-DSA with AEAD, KDF, custody, recipes, and CLI workflows.',
    )
    ..writeln('- It is not a validated cryptographic module.')
    ..writeln('- It does not provide:');

  for (final item in doesNotProvide) {
    buffer.writeln('  - $item');
  }

  buffer
    ..writeln()
    ..writeln('## Never Say')
    ..writeln();

  for (final claim in forbidden) {
    buffer.writeln('- $claim');
  }

  buffer
    ..writeln()
    ..writeln('## Recipes')
    ..writeln();

  for (final recipe in recipes) {
    buffer.writeln(
      '- ${recipe['name']}: ${recipe['apis']} (${recipe['apps']}).',
    );
  }

  buffer
    ..writeln()
    ..writeln('## Docs')
    ..writeln();

  for (final doc in docs) {
    buffer.writeln(
      '- [${doc['title']}](${_repoBlob(project, doc['url'] as String)}): '
      '${doc['description']}',
    );
  }

  return buffer.toString();
}

String _llmsFull(JsonMap manifest) {
  final project = _map(manifest['project']);
  final capabilities = _strings(manifest['capabilities']);
  final doesNotProvide = _strings(manifest['does_not_provide']);
  final evidence = _map(manifest['evidence_boundary']);
  final profiles = _maps(manifest['profiles']);
  final recipes = _maps(manifest['recipes']);
  final docs = _maps(manifest['docs']);
  final commands = _strings(manifest['validation_commands']);

  final buffer = StringBuffer()
    ..writeln(_mdComment())
    ..writeln('# ${project['title']}')
    ..writeln()
    ..writeln('Canonical URL: ${project['canonical_url']}')
    ..writeln('Repository: ${project['repository']}')
    ..writeln('Package: ${project['pub_dev']}')
    ..writeln('API docs: ${project['api_docs']}')
    ..writeln('Version: ${project['version']}')
    ..writeln()
    ..writeln('## Identity')
    ..writeln()
    ..writeln(project['summary'])
    ..writeln()
    ..writeln('## Capabilities')
    ..writeln();

  for (final item in capabilities) {
    buffer.writeln('- $item');
  }

  buffer
    ..writeln()
    ..writeln('## Does Not Provide')
    ..writeln();

  for (final item in doesNotProvide) {
    buffer.writeln('- $item');
  }

  buffer
    ..writeln()
    ..writeln('## Evidence Boundary')
    ..writeln()
    ..writeln(evidence['summary'])
    ..writeln()
    ..writeln('Allowed claims:');
  for (final claim in _strings(evidence['allowed_claims'])) {
    buffer.writeln('- $claim');
  }
  buffer.writeln();
  buffer.writeln('Forbidden claims:');
  for (final claim in _strings(evidence['forbidden_claims'])) {
    buffer.writeln('- $claim');
  }

  buffer
    ..writeln()
    ..writeln('## Profiles')
    ..writeln();
  for (final profile in profiles) {
    buffer.writeln(
      '- ${profile['name']}: ${profile['kem']} + ${profile['signature']} for ${profile['use']}.',
    );
  }

  buffer
    ..writeln()
    ..writeln('## Recipe Catalog')
    ..writeln();
  for (final recipe in recipes) {
    buffer
      ..writeln('### ${recipe['name']}')
      ..writeln()
      ..writeln('- Surface: ${recipe['surface']}')
      ..writeln('- Apps: ${recipe['apps']}')
      ..writeln('- APIs: ${recipe['apis']}')
      ..writeln('- Caveat: ${recipe['caveat']}')
      ..writeln();
  }

  buffer
    ..writeln('## Docs')
    ..writeln();
  for (final doc in docs) {
    buffer.writeln(
      '- [${doc['title']}](${_repoBlob(project, doc['url'] as String)}): '
      '${doc['description']}',
    );
  }

  buffer
    ..writeln()
    ..writeln('## Validation')
    ..writeln();
  for (final command in commands) {
    buffer.writeln('- `$command`');
  }

  return buffer.toString();
}

String _identityJson(JsonMap manifest) {
  final project = _map(manifest['project']);
  final identity = <String, Object?>{
    '@context': 'https://schema.org',
    '@type': 'SoftwareSourceCode',
    'name': project['short_title'],
    'alternateName': project['title'],
    'description': project['summary'],
    'url': project['canonical_url'],
    'codeRepository': project['repository'],
    'programmingLanguage': 'Dart',
    'runtimePlatform': ['Dart VM', 'Flutter', 'Serverpod', 'CLI'],
    'license': project['license'],
    'softwareVersion': project['version'],
    'applicationCategory': 'Cryptography composition library',
    'keywords': _strings(manifest['keywords']),
    'maintainer': {'@type': 'Organization', 'name': project['maintainer']},
    'sameAs': [
      project['repository'],
      project['pub_dev'],
      project['api_docs'],
      project['wiki'],
    ],
    'capabilities': _strings(manifest['capabilities']),
    'doesNotProvide': _strings(manifest['does_not_provide']),
    'evidenceBoundary': manifest['evidence_boundary'],
    'recipes': manifest['recipes'],
    'generatedBy': _generatedNotice,
    'dateModified': manifest['last_updated'],
  };
  return '${const JsonEncoder.withIndent('  ').convert(identity)}\n';
}

String _developerAi(JsonMap manifest) {
  final project = _map(manifest['project']);
  final commands = _strings(manifest['validation_commands']);
  final recipes = _maps(manifest['recipes']);

  final buffer = StringBuffer()
    ..writeln(_mdComment())
    ..writeln('# Developer AI Guidance For ${project['short_title']}')
    ..writeln()
    ..writeln(
      'Use this file when an AI coding agent needs scoped pqforge context.',
    )
    ..writeln()
    ..writeln('## Core Rule')
    ..writeln()
    ..writeln(
      'pqforge is an application composition package. Keep claims scoped to composition around pqcrypto; do not claim validation or certification.',
    )
    ..writeln()
    ..writeln('## Recipe Surfaces')
    ..writeln();
  for (final recipe in recipes) {
    buffer.writeln('- ${recipe['name']}: ${recipe['apis']}');
  }
  buffer
    ..writeln()
    ..writeln('## Required Verification')
    ..writeln();
  for (final command in commands) {
    buffer.writeln('- `$command`');
  }
  return buffer.toString();
}

String _faqAi(JsonMap manifest) {
  final faq = _maps(manifest['faq']);
  final buffer = StringBuffer()..writeln(_mdComment());
  for (final item in faq) {
    buffer
      ..writeln('## ${item['question']}')
      ..writeln()
      ..writeln(item['answer'])
      ..writeln();
  }
  return buffer.toString();
}

String _aiGuidance(JsonMap manifest) {
  final evidence = _map(manifest['evidence_boundary']);
  final buffer = StringBuffer()
    ..writeln(_mdComment())
    ..writeln('# AI Usage Policy For pqforge')
    ..writeln()
    ..writeln('Allowed summaries:')
    ..writeln(
      '- pqforge composes pqcrypto ML-KEM and ML-DSA for app workflows.',
    )
    ..writeln(
      '- pqforge includes AEAD, KDF, key wrapping, recipes, CLI, and hybrid helpers.',
    )
    ..writeln('- pqforge is not a validated cryptographic module.')
    ..writeln()
    ..writeln('Forbidden claims:');
  for (final claim in _strings(evidence['forbidden_claims'])) {
    buffer.writeln('- $claim');
  }
  return buffer.toString();
}

String _robotsAi(JsonMap manifest) {
  final project = _map(manifest['project']);
  return '''
User-agent: *
Allow: /

# Preferred AI entrypoints
Sitemap: ${project['canonical_url']}sitemap.xml
LLMS: ${project['canonical_url']}llms.txt
LLMS-Full: ${project['canonical_url']}llms-full.txt
''';
}

String _robots(JsonMap manifest) {
  final project = _map(manifest['project']);
  return '''
User-agent: *
Allow: /

Sitemap: ${project['canonical_url']}sitemap.xml
''';
}

String _copilotInstructions(JsonMap manifest) {
  final project = _map(manifest['project']);
  return '''
${_mdComment()}
# Copilot Instructions For ${project['short_title']}

- Treat `doc/` as the canonical documentation root.
- Keep generated visibility files in sync with `dart run tool/visibility/generate_visibility.dart`.
- Prefer named recipe helpers over hand-rolled message framing.
- Use wrapped secret keys for CLI examples.
- Do not claim FIPS validation, CMVP validation, certification, hard constant-time behavior, or hard memory erasure.
- Do not add RC4 or unauthenticated encryption.
''';
}

String _copilotCryptoInstructions(JsonMap manifest) {
  final recipes = _maps(manifest['recipes']);
  final buffer = StringBuffer()
    ..writeln(_mdComment())
    ..writeln('# pqforge Crypto Composition Rules')
    ..writeln()
    ..writeln('- ML-KEM establishes a shared secret; KEM-DEM uses HKDF + AEAD.')
    ..writeln('- ML-DSA signs; AES encrypts and never signs.')
    ..writeln(
      '- Public-key trust, identity vetting, and replay stores belong to the application.',
    )
    ..writeln('- Use these recipe surfaces:');
  for (final recipe in recipes) {
    buffer.writeln('  - ${recipe['name']}: ${recipe['apis']}');
  }
  return buffer.toString();
}

String _cursorRule(JsonMap manifest) {
  final project = _map(manifest['project']);
  return '''
---
description: pqforge repository guidance
alwaysApply: true
---

$_generatedNotice

Use `${project['short_title']}` as a composition package, not a primitive package.
Keep docs, README, wiki, and site claim boundaries synchronized.
Run `dart run tool/visibility/generate_visibility.dart --check` after visibility edits.
''';
}

String _windsurfRules(JsonMap manifest) {
  final project = _map(manifest['project']);
  return '''
$_generatedNotice

Repository: ${project['repository']}

Rules:
- Use named pqforge recipe helpers for app workflows.
- Keep CLI secret keys wrapped in examples.
- Keep generated visibility files current.
- Avoid validation/certification overclaims.
''';
}

