String _docCard(JsonMap project, JsonMap doc) {
  final href = _repoBlob(project, doc['url'] as String);
  return '<a href="${_html(href)}"><strong>${_html(doc['title'] as String)}</strong><span>${_html(doc['description'] as String)}</span></a>';
}

String _recipeCard(JsonMap recipe) {
  return '''
<article>
  <span>${_html(recipe['surface'] as String)}</span>
  <h3>${_html(recipe['name'] as String)}</h3>
  <p>${_html(recipe['apps'] as String)}</p>
  <code>${_html(recipe['apis'] as String)}</code>
</article>
''';
}

